import jwt
from jwt import PyJWTError
from typing import Optional, Dict

class JWTWrapper:
    def __init__(self, key_map: Dict[str, str]):
        """
        key_map: a dictionary mapping algorithm names (e.g., "HS256", "RS256") to their corresponding keys.
                 For HS algorithms, provide the shared secret; for RS algorithms, provide the public key.
        """
        self.key_map = key_map

    def verify_token(self, token: str, audience: Optional[str] = None, issuer: Optional[str] = None) -> Dict:
        """
        Verifies a JWT token and returns its payload.
        
        token: JWT token string.
        audience: Expected audience claim (optional).
        issuer: Expected issuer claim (optional).
        
        Raises:
            ValueError: If token is invalid, expired, or signed with an unsupported algorithm.
        
        Returns:
            The decoded payload as a dictionary.
        """
        try:
            header = jwt.get_unverified_header(token)
        except PyJWTError as exc:
            raise ValueError("Invalid JWT header.") from exc

        alg = header.get("alg")
        if not alg or alg not in self.key_map:
            raise ValueError(f"Unsupported signing algorithm: {alg}")

        key = self.key_map[alg]

        try:
            payload = jwt.decode(
                token,
                key=key,
                algorithms=[alg],
                audience=audience,
                issuer=issuer
            )
        except jwt.ExpiredSignatureError as exc:
            raise ValueError("Token has expired.") from exc
        except jwt.InvalidAudienceError as exc:
            raise ValueError("Invalid audience in token.") from exc
        except jwt.InvalidIssuerError as exc:
            raise ValueError("Invalid issuer in token.") from exc
        except PyJWTError as exc:
            raise ValueError("JWT verification failed.") from exc

        return payload

